import threading

class Account:
    def __init__(self, balance=0):
        self.balance = balance
        self.lock = threading.Lock()

    def deposit(self, amount):
        with self.lock:
            if amount > 0:
                self.balance += amount
                return True
            else:
                return False

    def withdraw(self, amount):
        with self.lock:
            if amount > 0 and self.balance >= amount:
                self.balance -= amount
                return True
            else:
                return False

    def get_balance(self):
        with self.lock:
            return self.balance